490	                      size_t                     top_p_size,
491	                      float*                     temperature,
492	                      float*                     repetition_penalty)
493	    {
494	        FT_LOG_INFO("Test %s", name.c_str());
495	        std::string tag    = fmtstr("Test %s T=%s", name.c_str(), std::is_same<T, float>::value ? "fp32" : "fp16");
496	        bool        passed = true;
497	        for (unsigned long long seed = 0; seed < max_seed; ++seed) {
498	            this->setup(seed);
499	            size_t     step = max_input_len;
