66	bool almostEqual(float a, float b, float atol = 1e-5, float rtol = 1e-8)
67	{
68	    // Params: a = value to compare and b = reference
69	    // This function follows implementation of numpy.isclose(), which checks
70	    //   abs(a - b) <= (atol + rtol * abs(b)).
71	    // Note that the inequality above is asymmetric where b is considered as
72	    // a reference value. To account into both absolute/relative errors, it
73	    // uses absolute tolerance and relative tolerance at the same time. The
74	    // default values of atol and rtol borrowed from numpy.isclose(). For the
75	    // case of nan value, the result will be true.
76	    if (isnan(a) && isnan(b)) {
77	        return true;
78	    }
79	    return fabs(a - b) <= (atol + rtol * fabs(b));
80	}
