83	bool checkResult(std::string name, T* out, T*ref, size_t size, float atol, float rtol) {
84	    size_t failures = 0;
85	    float relative_gap = 0.0f;;
86	
87	    for (size_t i = 0; i < size; ++i) {
88	        // The values for the output and the reference.
89	        float a = (float)out[i];
90	        float b = (float)ref[i];
91	
92	        bool ok = almostEqual(a, b, atol, rtol);
93	        // Print the error.
94	        if (!ok && failures < 4) {
95	            FT_LOG_ERROR(">> invalid result for i=%lu:", i);
96	            FT_LOG_ERROR(">>    found......: %10.6f", a);
97	            FT_LOG_ERROR(">>    expected...: %10.6f", b);
98	            FT_LOG_ERROR(">>    error......: %.6f", fabsf(a - b));
99	            FT_LOG_ERROR(">>    tol........: %.6f", atol + rtol * fabs(b));
100	        }
101	        // Update the number of failures.
102	        failures += ok ? 0 : 1;
103	        // Update the relative gap.
104	        relative_gap += fabsf(a - b) / (fabsf(b) + EPSILON);
105	    }
106	
107	    relative_gap /= size;
108	
109	    // Allow not matched up to 1% elements.
110	    size_t tol_failures = (size_t)(0.01 * size);
111	    FT_LOG_INFO("check...%6s : %-50s (failures: %.2f%% atol: %.2e rtol: %.2e rel_gap: %.2e%%)",
112	                failures <= tol_failures ? "....OK" : "FAILED", name.c_str(),
113	                100. * failures / size, atol, rtol, 100. * relative_gap);
114	    return failures <= tol_failures;
115	}
