185	bool almostEqual(float a, float b, float atol = 1e-5, float rtol = 1e-8)
186	{
187	    // Params: a = value to compare and b = reference
188	    // This function follows implementation of numpy.isclose(), which checks
189	    //   abs(a - b) <= (atol + rtol * abs(b)).
190	    // Note that the inequality above is asymmetric where b is considered as
191	    // a reference value. To account into both absolute/relative errors, it
192	    // uses absolute tolerance and relative tolerance at the same time. The
193	    // default values of atol and rtol borrowed from numpy.isclose(). For the
194	    // case of nan value, the result will be true.
195	    if (isnan(a) && isnan(b)) {
196	        return true;
197	    }
198	    return fabs(a - b) <= (atol + rtol * fabs(b));
199	}
